# Terraform: GitHub environment configuration
# (or set via GitHub UI: Settings → Environments)

resource "github_repository_environment" "pre_prod" {
  repository  = "your-repo"
  environment = "pre-prod"

  reviewers {
    teams = [data.github_team.tech_leads.id]
  }

  deployment_branch_policy {
    protected_branches     = true
    custom_branch_policies = false
  }
}

resource "github_repository_environment" "production" {
  repository  = "your-repo"
  environment = "production"

  reviewers {
    teams = [data.github_team.engineering_managers.id]
  }

  wait_timer = 30   # minutes after the pre-prod deployment

  deployment_branch_policy {
    protected_branches     = true
    custom_branch_policies = false
  }
}
